import React, { useEffect } from 'react';
import styled from 'styled-components';
import AOS from 'aos';
import 'aos/dist/aos.css';
import Footer from '../components/Footer';
import { useTheme } from '../context/ThemeContext';
import PageWrapper from '../components/PageWrapper';

const EventsPage = styled.div`
  min-height: 100vh;
  background: #000;
  padding-top: 80px;
`;

const EventsSection = styled.section`
  padding: 100px 10%;
`;

const Header = styled.div`
  text-align: center;
  margin-bottom: 60px;

  h2 {
    font-size: 3rem;
    color: #00FFFF;
    margin-bottom: 20px;
    position: relative;
    display: inline-block;

    &::after {
      content: '';
      position: absolute;
      bottom: -10px;
      left: 50%;
      transform: translateX(-50%);
      width: 80px;
      height: 4px;
      background: linear-gradient(to right, #00FFFF, #00BFFF);
      border-radius: 2px;
    }
  }
`;

const EventGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 30px;
`;

const EventCard = styled.div`
  background: ${props => props.theme.cardBackground};
  border: 1px solid ${props => props.theme.cardBorder};
  border-radius: 15px;
  padding: 20px;
  margin: 20px 0;
  transition: all 0.3s ease;

  h3 {
    color: ${props => props.theme.primary};
  }

  p {
    color: ${props => props.theme.text};
  }

  &:hover {
    transform: translateY(-5px);
    box-shadow: ${props => props.theme.shadow};
  }

  img {
    width: 100%;
    height: 200px;
    object-fit: cover;
  }

  .content {
    padding: 20px;

    h3 {
      margin-bottom: 10px;
      font-size: 1.5rem;
    }

    p {
      margin-bottom: 20px;
    }

    .date {
      color: ${props => props.theme.primary};
      font-weight: bold;
    }

    .status {
      display: inline-block;
      padding: 5px 15px;
      border-radius: 15px;
      font-size: 0.9rem;
      margin-top: 10px;

      &.upcoming {
        background-color: rgb(102, 255, 85);
        color: black;
      }

      &.past {
        background-color: rgba(255, 255, 255, 0.2);
        color: white;
      }
    }
  }
`;

const Events = () => {
  const { theme } = useTheme();

  useEffect(() => {
    AOS.init({
      duration: 1000,
      once: true,
      mirror: false
    });
  }, []);

  const events = [
    {
      title: "OPTIMUS ARENA 2025",
      description: "Our annual flagship hackathon event. Join us for 48 hours of coding, innovation, and fun!",
      image: require("../assets/event1.jpeg"),
      date: "May 29, 2025",
      status: "upcoming"
    }
    // Add more events here
  ];

  return (
    <PageWrapper theme={theme}>
      <EventsPage>
        <EventsSection>
          <Header>
            <h2 style={{ color: theme.primary }} data-aos="fade-up">Our Events</h2>
          </Header>
          <EventGrid>
            {events.map((event, index) => (
              <EventCard key={index} data-aos="fade-up" data-aos-delay={100 * (index + 1)}>
                <img src={event.image} alt={event.title} />
                <div className="content">
                  <h3>{event.title}</h3>
                  <p>{event.description}</p>
                  <div className="date">{event.date}</div>
                  <span className={`status ${event.status}`}>
                    {event.status.charAt(0).toUpperCase() + event.status.slice(1)}
                  </span>
                </div>
              </EventCard>
            ))}
          </EventGrid>
        </EventsSection>
        <Footer />
      </EventsPage>
    </PageWrapper>
  );
};

export default Events;
